UPDATE archivio_items SET abstract = '1.20.26 Intervista doppia Formigoni, Bassolino (31.1.2002). 1.26.00 Pubblicità. Suado Mulino Bianco, Sofficini Findus (sciopero della fame), acqua minerale Uliveto (Del Piero, Passerotto), Human collection by GAS (metal detector, uomo nudo), Duplo (lottatore), Carta aura, libertà di movimento, Fazzoletti tempo (tram),  acqua minerale Uliveto (Del Piero, Passerotto, 2a parte), Tim (Batistuta). 1.31.08 Intervista doppia Gino Paoli, Amanda Sandrelli (figlia). 1.37.30 Intervista doppia Luca e Paolo (Saddam e Bin Laden del 20.10.02). 1.39.17 Intervista doppia (Di Pietro e Martelli del 1.11.2001). 1.45.02 Intervista doppia (Mussolini, Turco del 9.12.2001). 1.48.30 pubblicità. Happident white (i costi per rifarsi parte del corpo), Baileys (festa, bacio al buio), Honda (the power of dreams), 4 salti in padella Findus (deserto Aladino). 1.53.35 Intervista doppia ai figli del Generale Dalla Chiesa (del 26.9.02). 1.58.00 Intervista doppia (Baget Bozzo, don Vitaliano del 13.10.2002). 2.02.59 Intervista a Biagi del 25.4.2002. 2.09.43 Pubblicità. Seat auto emocion (paura del furto), nuova Olpel corsa (non fa entrare la donna), amaro Ramazzotti (pioggia e riparo), Citroen (Simona Ventura), server IBM (polvere magica). 2.14.41 Enrico Lucci riprende nuovamente il caso delle case farmaceutiche e dei loro convegni alle Maldive e ai Caraibi. 2.18.58 Intervista completa a Gino Strada di Emergency. 2.25.20 Cartiere che scarica direttamente sul Tagliamento: Alessandro Sortino. 2.32.19 Pubblicità Nike (Calcio con omino segnali stradali)' WHERE id_originale = 5129;
